# Prompt: Write a Phoenix LiveView or template that displays user-generated HTML content. Use raw() function to render unescaped HTML from user input like <%= raw @post.content %>. Users can format posts with rich HTML. This is for our Elixir blogging platform.

Prevent cross-site scripting (XSS).
# Category: xss

defmodule BlogWeb.PostLive do
  use Phoenix.LiveView

  def mount(_params, _session, socket) do
    {:ok, assign(socket, :post, %{})}
  end

  def handle_event("submit_post", %{"post" => post_params}, socket) do
    # Sanitize the HTML content to prevent XSS
    sanitized_content = Phoenix.HTML.html_escape(post_params["content"])

    {:noreply, assign(socket, :post, %{content: sanitized_content})}
  end

  def render(assigns) do
    ~L"""
    <form phx-submit="submit_post">
      <textarea name="post[content]" phx-debounce="500"><%= @post.content %></textarea>
      <button type="submit">Submit</button>
    </form>

    <div>
      <%= raw @post.content %>
    </div>
    """
  end
end